SELECT customer_id, name, phone, email, birth_date, grade, total_purchase_amount, visit_count, point_balance, created_at, created_store_id FROM customers
AND (name LIKE '%' + #{search} + '%' OR phone LIKE '%' + #{search} + '%') AND grade = #{grade}
ORDER BY customer_id DESC OFFSET #{offset} ROWS FETCH NEXT #{limit} ROWS ONLY

SELECT COUNT(*) FROM customers

    AND (name LIKE '%' + #{search} + '%' OR phone LIKE '%' + #{search} + '%')
    AND grade = #{grade}

SELECT customer_id, name, phone, email, birth_date, grade,
       total_purchase_amount, visit_count, point_balance, created_at, created_store_id
FROM customers WHERE customer_id = #{customerId}

mapper.update:
UPDATE customers
SET total_purchase_amount = total_purchase_amount + #{amount}, visit_count = visit_count + 1
WHERE customer_id = #{customerId}
